import {describe,it,expect} from 'vitest';
import request from 'supertest';
import {app} from '../app';
import {withTx} from '../../tests/setup/per-worker-db';

describe('GET /folders/:id/tree',()=>{
  it('detects cycle and returns 422',async()=>{
    await withTx(async(c)=>{
      await c.query("INSERT INTO folders(id,parent_id) VALUES('a',NULL),('b','a'),('c','b')");
      await c.query("UPDATE folders SET parent_id='c' WHERE id='a'"); // create cycle
      const r=await request(app).get('/folders/a/tree').expect(422);
      expect(r.body.error).toMatch(/cycle/i);
    });
  });
  it('bounds at max depth',async()=>{
    await withTx(async(c)=>{
      let prev:string|null=null;
      for(let i=0;i<50;i++){const id=`f${i}`;await c.query("INSERT INTO folders(id,parent_id) VALUES($1,$2)",[id,prev]);prev=id;}
      const r=await request(app).get('/folders/f0/tree?maxDepth=10').expect(200);
      expect(JSON.stringify(r.body).match(/children/g)?.length).toBeLessThanOrEqual(10);
    });
  });
});

import {describe,it} from 'vitest';
import fc from 'fast-check';
import {createInMemoryStore,rateLimit} from './rate-limit';
import {FakeClock} from '../clock';

describe('rate limiter cap',()=>{
  it('never exceeds max regardless of concurrency',async()=>{
    await fc.assert(fc.asyncProperty(fc.array(fc.integer({min:0,max:1000}),{maxLength:100}),fc.integer({min:1,max:20}),async(times,max)=>{
      const clock=new FakeClock(0);
      const store=createInMemoryStore();
      let accepted=0;
      for(const t of times){
        clock.set(t);
        const count=await store.incr('k',60_000,clock.now());
        if(count<=max)accepted++;
      }
      const windowed=accepted;
      // For inputs all in same 60s window, accepted should be ≤ max
      const sameWindow=times.every(t=>t<60_000);
      if(sameWindow)return accepted<=max;
      return true;
    }),{numRuns:200});
  });
});

