import {useEffect,useState} from 'react';
export function useIsVisible(){
  const [v,setV]=useState(()=>document.visibilityState==='visible');
  useEffect(()=>{
    const on=()=>setV(document.visibilityState==='visible');
    document.addEventListener('visibilitychange',on);
    return ()=>document.removeEventListener('visibilitychange',on);
  },[]);
  return v;
}

import {describe,it,expect,act} from 'vitest';
import {renderHook} from '@testing-library/react';
import {useIsVisible} from './useIsVisible';

describe('useIsVisible',()=>{
  it('updates on visibilitychange',()=>{
    Object.defineProperty(document,'visibilityState',{configurable:true,value:'visible'});
    const {result}=renderHook(()=>useIsVisible());
    expect(result.current).toBe(true);
    Object.defineProperty(document,'visibilityState',{configurable:true,value:'hidden'});
    act(()=>{document.dispatchEvent(new Event('visibilitychange'));});
    expect(result.current).toBe(false);
  });
});

