import {useEffect} from 'react';
export function useEvents(url:string,onMessage:(d:unknown)=>void){
  useEffect(()=>{
    const es=new EventSource(url);
    es.onmessage=(e)=>onMessage(JSON.parse(e.data));
    return ()=>es.close();
  },[url,onMessage]);
}

