const ALLOWED:Record<string,string[]>={pending:['paid','cancelled'],paid:['shipped','refunded'],shipped:['delivered'],delivered:[],cancelled:[],refunded:[]};
export function transition(from:string,to:string):string{
  if(!ALLOWED[from]?.includes(to))throw new Error(`invalid: ${from}→${to}`);
  return to;
}

import {describe,it,expect} from 'vitest';
import fc from 'fast-check';
import {transition} from './state-machine';

const STATES=['pending','paid','shipped','delivered','cancelled','refunded'];

describe('transition',()=>{
  it('rejects disallowed pairs',()=>{
    fc.assert(fc.property(fc.constantFrom(...STATES),fc.constantFrom(...STATES),(from,to)=>{
      const allowed=ALLOWED[from]?.includes(to);
      try{transition(from,to);return allowed;}
      catch{return !allowed;}
    }),{numRuns:200});
  });
});

