test('session cookie expires in ~1h',async({page,context})=>{
  await page.goto('/login');
  await page.getByLabel(/email/i).fill('a@b.co');
  await page.getByLabel(/password/i).fill('x');
  await page.getByRole('button').click();
  const cookies=await context.cookies();
  const session=cookies.find(c=>c.name==='session');
  expect(session).toBeDefined();
  const remaining=session!.expires-Date.now()/1000;
  expect(remaining).toBeGreaterThan(3500);
  expect(remaining).toBeLessThan(3700);
});

